=== ./feature_stage_plan.proto ===
syntax = "proto3";
import "feature_state.proto";

option csharp_namespace = "OneMoreTaskTracker.Proto.Features";
package mr_helper.features;

// Canonical per-stage plan message shared by every FeatureDto carrier.
// Mirrors api-contract.md: exactly 5 entries per feature (one per FeatureState
// ordinal), upserted atomically by UpdateFeatureHandler.
//
// Wire conventions:
//   planned_start / planned_end = ""   → null (matches the existing planned_*
//                                        string-empty convention on FeatureDto).
//   performer_user_id           =  0   → unassigned (proto3 scalar default;
//                                        the gateway surfaces this as `null`).
message FeatureStagePlan {
  FeatureState stage              = 1;
  string       planned_start      = 2;
  string       planned_end        = 3;
  int32        performer_user_id  = 4;
  // Per-stage optimistic-concurrency token (see api-contract.md
  // § "Optimistic Concurrency"). Bumped by every stage-scoped PATCH.
  int32        version            = 5;
}

=== ./feature_state.proto ===
syntax = "proto3";

option csharp_namespace = "OneMoreTaskTracker.Proto.Features";
package mr_helper.features;

// Ordinals mirror the C# FeatureState enum (CsApproving = 0) to match the
// Tasks service's task_state.proto style (see task_state.proto, which also
// forgoes the proto3 *_UNSPECIFIED = 0 convention to share ordinals with
// the C# enum). Spec 02 § "FeatureState proto enum ordinals" explicitly
// tolerates this and directs us to replicate task_state.proto.
enum FeatureState {
  CS_APPROVING = 0;
  DEVELOPMENT = 1;
  TESTING = 2;
  ETHALON_TESTING = 3;
  LIVE_RELEASE = 4;
}

